description:
Configure the PromptWorld Jinja environment with a custom formatter that detects JinjaPromptValue and routes it through the render pipeline.

Location: crates/baml-bridge/src/prompt/jinja.rs or prompt/world.rs

```rust
use minijinja::{Environment, Value, Error};

/// Configure the Jinja environment for prompt rendering
pub fn configure_prompt_env(env: &mut Environment<'static>) {
    // Set strict undefined behavior
    env.set_undefined_behavior(minijinja::UndefinedBehavior::Strict);

    // Install custom formatter
    env.set_formatter(prompt_formatter);
}

/// Custom formatter that handles JinjaPromptValue specially
fn prompt_formatter(
    out: &mut minijinja::Output<'_>,
    state: &minijinja::State<'_, '_>,
    value: &Value,
) -> Result<(), Error> {
    // Check if this is a JinjaPromptValue
    if let Some(obj) = value.as_object() {
        if let Some(jpv) = obj.downcast_ref::<JinjaPromptValue>() {
            // Route through render pipeline
            match jpv.pv.world.render_prompt_value(&jpv.pv, None) {
                Ok(output) => {
                    out.write_str(&output.text)?;
                    return Ok(());
                }
                Err(e) => {
                    return Err(Error::new(
                        minijinja::ErrorKind::InvalidOperation,
                        e.message.clone()
                    ));
                }
            }
        }
    }

    // Handle None specially
    if value.is_none() {
        out.write_str('null')?;
        return Ok(());
    }

    // Default formatting for other values
    minijinja::escape_formatter(out, state, value)
}
```

This is the critical integration point - when a template does {{ value }}, if value is a JinjaPromptValue, it goes through render_prompt_value instead of default Display.
